import React, { useEffect, useState } from 'react';
import { TrendingUp, TrendingDown, RefreshCw, Activity, DollarSign, BarChart3 } from 'lucide-react';
import { useMarketStore } from '../store/marketStore';
import { usePortfolioStore } from '../store/portfolioStore';
import { PriceChart, MarketOverviewChart } from '../components/Charts/ChartComponents';
import { CompactCryptoList } from '../components/Crypto/CryptoTable';
import toast from 'react-hot-toast';

/**
 * Dashboard Page Component
 * Main landing page showing overview of crypto market and user portfolio
 */
const Dashboard: React.FC = () => {
  const [isRefreshing, setIsRefreshing] = useState(false);
  
  const {
    topCryptos,
    globalMetrics,
    priceHistory,
    isLoading: marketLoading,
    fetchTopCryptos,
    fetchGlobalMetrics,
    fetchPriceHistory,
    setSelectedCrypto,
    startAutoRefresh,
    stopAutoRefresh,
  } = useMarketStore();

  const {
    totalValue,
    totalChangePercent24h,
    assets,
    calculateTotals,
  } = usePortfolioStore();

  useEffect(() => {
    // Fetch initial data
    const loadData = async () => {
      await Promise.all([
        fetchTopCryptos(10),
        fetchGlobalMetrics(),
      ]);
      
      // Fetch price history for Bitcoin
      if (topCryptos.length > 0) {
        const btc = topCryptos.find(crypto => crypto.symbol === 'BTC');
        if (btc) {
          await fetchPriceHistory(btc.symbol, '24h');
        }
      }
    };

    loadData();
    calculateTotals();
    
    // Start real-time price updates
    startAutoRefresh();
    
    // Cleanup on unmount
    return () => {
      stopAutoRefresh();
    };
  }, [fetchTopCryptos, fetchGlobalMetrics, fetchPriceHistory, calculateTotals, startAutoRefresh, stopAutoRefresh]);

  const handleRefresh = async () => {
    setIsRefreshing(true);
    try {
      await Promise.all([
        fetchTopCryptos(10),
        fetchGlobalMetrics(),
      ]);
      toast.success('Data refreshed successfully');
    } catch (error) {
      toast.error('Failed to refresh data');
    } finally {
      setIsRefreshing(false);
    }
  };

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(value);
  };

  const formatLargeCurrency = (value: number) => {
    if (value >= 1e12) {
      return `$${(value / 1e12).toFixed(2)}T`;
    } else if (value >= 1e9) {
      return `$${(value / 1e9).toFixed(2)}B`;
    } else if (value >= 1e6) {
      return `$${(value / 1e6).toFixed(2)}M`;
    } else {
      return formatCurrency(value);
    }
  };

  const formatPercent = (value: number) => {
    return `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
  };

  // Get Bitcoin price history for chart
  const btcHistory = priceHistory['BTC'] || [];
  const btcData = topCryptos.find(crypto => crypto.symbol === 'BTC');

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold gradient-text">
          Crypto Analytics Dashboard
        </h1>
        <div className="flex items-center space-x-4">
          <div className="flex items-center space-x-2 text-sm text-slate-400">
            <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></div>
            <span>🚀 Live Multi-API Real-Time • Auto-updating every 3s</span>
          </div>
          <button
            onClick={handleRefresh}
            disabled={isRefreshing || marketLoading}
            className="flex items-center space-x-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white rounded-lg transition-colors"
          >
            <RefreshCw className={`w-4 h-4 ${isRefreshing ? 'animate-spin' : ''}`} />
            <span>Refresh</span>
          </button>
        </div>
      </div>

      {/* Market Overview Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="card">
          <div className="flex items-center justify-between mb-2">
            <h3 className="text-lg font-semibold text-slate-300">Total Market Cap</h3>
            <DollarSign className="w-5 h-5 text-green-400" />
          </div>
          <p className="text-2xl font-bold text-green-400">
            {globalMetrics ? formatLargeCurrency(globalMetrics.totalMarketCap) : '$2.1T'}
          </p>
          <p className={`text-sm ${
            (globalMetrics?.totalMarketCapChange24h || 2.4) >= 0 ? 'text-green-400' : 'text-red-400'
          }`}>
            {formatPercent(globalMetrics?.totalMarketCapChange24h || 2.4)}
          </p>
        </div>
        
        <div className="card">
          <div className="flex items-center justify-between mb-2">
            <h3 className="text-lg font-semibold text-slate-300">24h Volume</h3>
            <BarChart3 className="w-5 h-5 text-blue-400" />
          </div>
          <p className="text-2xl font-bold text-blue-400">
            {globalMetrics ? formatLargeCurrency(globalMetrics.total24hVolume) : '$89.2B'}
          </p>
          <p className={`text-sm ${
            (globalMetrics?.total24hVolumeChange || 1.8) >= 0 ? 'text-green-400' : 'text-red-400'
          }`}>
            {formatPercent(globalMetrics?.total24hVolumeChange || 1.8)}
          </p>
        </div>
        
        <div className="card">
          <div className="flex items-center justify-between mb-2">
            <h3 className="text-lg font-semibold text-slate-300">BTC Dominance</h3>
            <Activity className="w-5 h-5 text-yellow-400" />
          </div>
          <p className="text-2xl font-bold text-yellow-400">
            {globalMetrics ? `${globalMetrics.btcDominance.toFixed(1)}%` : '42.3%'}
          </p>
          <p className="text-sm text-slate-400">
            ETH: {globalMetrics ? `${globalMetrics.ethDominance.toFixed(1)}%` : '15.5%'}
          </p>
        </div>
        
        <div className="card">
          <div className="flex items-center justify-between mb-2">
            <h3 className="text-lg font-semibold text-slate-300">Fear & Greed</h3>
            <Activity className="w-5 h-5 text-purple-400" />
          </div>
          <p className="text-2xl font-bold text-purple-400">
            {globalMetrics?.fearGreedIndex || 65}
          </p>
          <p className="text-sm text-slate-400">
            {globalMetrics?.fearGreedValue || 'Greed'}
          </p>
        </div>
      </div>

      {/* Portfolio Overview & Bitcoin Chart */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Portfolio Overview */}
        <div className="card">
          <h2 className="text-xl font-semibold mb-4 flex items-center">
            <DollarSign className="w-5 h-5 mr-2" />
            Portfolio Overview
          </h2>
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <span className="text-slate-400">Total Value</span>
              <span className="text-xl font-bold text-white">
                {formatCurrency(totalValue)}
              </span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-slate-400">24h Change</span>
              <span className={`font-medium ${
                totalChangePercent24h >= 0 ? 'text-green-400' : 'text-red-400'
              }`}>
                {totalChangePercent24h >= 0 ? (
                  <TrendingUp className="w-4 h-4 inline mr-1" />
                ) : (
                  <TrendingDown className="w-4 h-4 inline mr-1" />
                )}
                {formatPercent(totalChangePercent24h)}
              </span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-slate-400">Total Assets</span>
              <span className="font-medium text-white">{assets.length}</span>
            </div>
            <div className="pt-4 border-t border-slate-700">
              <div className="flex justify-between text-sm">
                <span className="text-slate-400">Performance</span>
                <span className={totalChangePercent24h >= 0 ? 'text-green-400' : 'text-red-400'}>
                  {totalChangePercent24h >= 0 ? 'Profitable' : 'Loss'}
                </span>
              </div>
            </div>
          </div>
        </div>

        {/* Bitcoin Price Chart - Simple Chart with Real-Time Data */}
        <div className="card">
          <h2 className="text-xl font-semibold mb-4 flex items-center">
            <BarChart3 className="w-5 h-5 mr-2" />
            Bitcoin Price (24h) - Real-Time
          </h2>
          {btcHistory.length > 0 ? (
            <div className="h-64">
              <PriceChart
                data={btcHistory}
                symbol="BTC"
                timeframe="24h"
                className="h-full"
              />
            </div>
          ) : (
            <div className="h-64 flex items-center justify-center text-slate-400">
              <div className="text-center">
                <BarChart3 className="w-12 h-12 mx-auto mb-2 opacity-50" />
                <p>Loading real-time chart data...</p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Top Cryptocurrencies & Quick Actions */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Top Cryptocurrencies */}
        <div className="lg:col-span-2 card">
          <h2 className="text-xl font-semibold mb-4">Top Cryptocurrencies</h2>
          {topCryptos.length > 0 ? (
            <CompactCryptoList
              data={topCryptos.slice(0, 8)}
              onCryptoSelect={(crypto) => {
                setSelectedCrypto(crypto.symbol);
                // Navigate to analytics page with selected crypto
                window.location.href = `/analytics?crypto=${crypto.symbol}`;
              }}
              showRank={true}
            />
          ) : (
            <div className="text-center py-8 text-slate-400">
              Loading cryptocurrency data...
            </div>
          )}
        </div>

        {/* Quick Actions */}
        <div className="card">
          <h2 className="text-xl font-semibold mb-4">Quick Actions</h2>
          <div className="space-y-3">
            <button 
              className="btn-primary w-full"
              onClick={() => window.location.href = '/predictions'}
            >
              View Predictions
            </button>
            <button 
              className="btn-secondary w-full"
              onClick={() => window.location.href = '/portfolio'}
            >
              Analyze Portfolio
            </button>
            <button 
              className="btn-secondary w-full"
              onClick={() => window.location.href = '/analytics'}
            >
              Market Sentiment
            </button>
          </div>
          
          {/* Recent Activity */}
          <div className="mt-6">
            <h3 className="text-lg font-medium mb-3">Recent Activity</h3>
            <div className="space-y-3">
              <div className="flex justify-between items-center p-3 bg-slate-700 rounded-lg">
                <div>
                  <p className="font-medium text-sm">
                    {btcData ? `Bitcoin at ${formatCurrency(btcData.price)}` : 'Bitcoin Price Alert'}
                  </p>
                  <p className="text-xs text-slate-400">
                    {btcData ? `${formatPercent(btcData.priceChangePercent24h)} (24h)` : 'BTC monitoring active'}
                  </p>
                </div>
                <span className="text-xs text-slate-500">Live</span>
              </div>
              
              <div className="flex justify-between items-center p-3 bg-slate-700 rounded-lg">
                <div>
                  <p className="font-medium text-sm">Portfolio Sync</p>
                  <p className="text-xs text-slate-400">
                    {assets.length} assets tracked
                  </p>
                </div>
                <span className="text-xs text-slate-500">Active</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Market Overview Chart - Simple Chart with Real-Time Data */}
      <div className="card">
        <h2 className="text-xl font-semibold mb-4 flex items-center">
          <Activity className="w-5 h-5 mr-2" />
          Market Overview - Real-Time Price Updates
        </h2>
        <div className="h-96">
          <MarketOverviewChart
            data={topCryptos.slice(0, 8).map(crypto => ({
              symbol: crypto.symbol,
              marketCap: crypto.marketCap || 0,
              change24h: crypto.priceChange24h
            }))}
            className="h-full"
          />
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
